/* lowlevel_file.c */
#include "lowlevel_file.h"
#include <string.h> // for memcpy and memset
#include <unistd.h>
#include <stdio.h>

unsigned metadata_read_count = 0;
unsigned metadata_write_count = 0;
unsigned data_read_count = 0;
unsigned data_write_count = 0;

void file_allocate(struct indextb *tb, unsigned offset, unsigned len) {
    if (len == 0) return;
    unsigned start_page = offset / PG_SIZE;
    unsigned end_page = (offset + len - 1) / PG_SIZE;

    metadata_read_count++; // Increment read count
    int has_write_metadata = 0;
    for (unsigned page = start_page; page <= end_page; page++) {
        if (tb->index[page] == NULL) {
            tb->index[page] = malloc_page();
            has_write_metadata = 1; // Mark that we wrote metadata
        }
    }
    if (has_write_metadata) {
        metadata_write_count++; // Increment write count
    }
}

void file_read(struct indextb *tb, unsigned offset, unsigned len, char *data) {
    unsigned current_offset = offset;
    unsigned remaining = len;
    unsigned page;

    metadata_read_count++; // Increment read count
    while (remaining > 0) {
        page = current_offset / PG_SIZE;
        unsigned offset_in_page = current_offset % PG_SIZE;
        unsigned bytes_in_page = PG_SIZE - offset_in_page;
        unsigned bytes_to_copy = (bytes_in_page < remaining) ? bytes_in_page : remaining;

        if (tb->index[page] == NULL) {
            memset(data, 0, bytes_to_copy);
        } else {
            memcpy(data, tb->index[page] + offset_in_page, bytes_to_copy);
            data_read_count++; // Increment read count
        }

        data += bytes_to_copy;
        current_offset += bytes_to_copy;
        remaining -= bytes_to_copy;
    }
}

void file_write(struct indextb *tb, unsigned offset, unsigned len, const char *data) {
    unsigned current_offset = offset;
    unsigned remaining = len;
    unsigned page;

    metadata_read_count++; // Increment read count
    int has_write_metadata = 0;
    while (remaining > 0) {
        page = current_offset / PG_SIZE;
        unsigned offset_in_page = current_offset % PG_SIZE;
        unsigned bytes_in_page = PG_SIZE - offset_in_page;
        unsigned bytes_to_copy = (bytes_in_page < remaining) ? bytes_in_page : remaining;

        if (tb->index[page] == NULL) {
            if (data == NULL) {
                tb->index[page] = malloc_page();
                has_write_metadata = 1; // Mark that we wrote metadata
                memset(tb->index[page] + offset_in_page, 0, bytes_to_copy);
                data_write_count++; // Increment write count
            }
        } else {
            if (data == NULL) {
                memset(tb->index[page] + offset_in_page, 0, bytes_to_copy);
            } else {
                memcpy(tb->index[page] + offset_in_page, data, bytes_to_copy);
            }
            data_write_count++; // Increment write count
        }

        if (data != NULL) {
            data += bytes_to_copy;
        }
        current_offset += bytes_to_copy;
        remaining -= bytes_to_copy;
    }
    if (has_write_metadata) {
        metadata_write_count++; // Increment write count
    }
}

void clear_file(struct inode *node, unsigned start, unsigned len) {
    file_write(node->file, start, len, NULL);
}